// Solution
function solve<T>(x: T): T | string {
  if (typeof x === 'number') {
    return x;
  } else if (typeof x === 'string') {
    return 'Input is a number';
  } else {
    return 'Input is not a number';
  }
}

solutions.python:
// Solution
class Solution:
  def solve(self, x: int | str) -> int | str:
    if isinstance(x, int):
      return x
    elif isinstance(x, str):
      return 'Input is a number'
    else:
      return 'Input is not a number'
